async create_answer(sdp) {
 this.signaling_queue = this.signaling_queue.then(
 () => this.create_answer_task(sdp)
 );
 return this.signaling_queue;
}
async create_answer_task(sdp) {
 try {
 await this.subscriber_pc.setRemoteDescription(new RTCSessionDescription({
 type: 'offer',
 sdp: sdp
 }));
 const answer = await this.subscriber_pc.createAnswer();
 await this.subscriber_pc.setLocalDescription(answer);
 this.ws.send(JSON.stringify({
 kind: "rtc",
 target: 'subscriber',
 type: 'answer',
 sdp: answer.sdp
 }));
 } catch (error) {
 console.error("Ошибка при обработке SFU Offer:", error);
 }
}
Нам важна последовательность поскольку, если начать одновременно выполнять два асинхронных шага (например, параллельно обрабатывать два разных
Offer
от сервера), свойство
signalingState
у браузерного объекта связи уйдет в конфликт (например, изменится на
have-remote-offer
посреди выполнения первого процесса), и браузер выбросит неустранимую ошибку. Очередь гарантирует, что текущая транзакция изменения связи завершится до того, как начнется следующая.
