impl Actor for PacketForwarder {
 type Message = AudioPacketForwarderMessage;
 async fn handle(&mut self, ctx: &mut crate::actor::Ctx<'_, Self>, packet: Self::Message) {
 if let Err(e) = self.forward(packet.packet).await {
 self.stop(ctx).await;
 }
 }
}
Отключение пользователя
В случае отключения пользователя пользователя актор юзер будет остановлен, дропнет подписчика и паблишера, и перешлет сообщение комнате о том, что необходимо удалить юзера и оповестить остальным пользователей.
async fn stopping(self, _: &Ctx<'_, Self>) {
 self.subscriber.try_terminate().await;
 self.publisher.try_terminate().await;
 let _ = self.room.send(RoomMessage::Leave { 
 peer_id: self.peer_id 
 }).await;
}
RoomMessage::Leave { peer_id } => {
 self.peers.remove(&peer_id);
 for (_, Peer { user, .. }) in self.peers.iter() {
 user.send(UserMessage::Unsubscribe { user_id: peer_id }).await;
 }
}
После чего остальные пользователи отключат акторов подписок на вышедшего юзера.
async fn disconnect_from_user(&mut self, speaker_id: Uuid) -> Result<(), Error> {
 let audio_subscription = self.audio_subscriptions
 .remove(&speaker_id)
 .ok_or(Error::SystemError { message: "subscription not found".into() })?;
 audio_subscription.terminate().await?;
 let video_subscription = self.video_subscriptions
 .remove(&speaker_id)
 .ok_or(Error::SystemError { message: "subscription not found".into() })?;
 video_subscription.terminate().await?;
 Ok(())
}
В результате отключения акторы подписки пошлют сообщение об отписке RtpPacketGatewayRouter и удалят трек из соединения подписчика.
Выход в свет
Для того чтобы проверить, что все действительно работает правильно, нам нужно убедиться, что все будет работать также не только в локальной сети, но и в глобальном интернете.
Чтобы протестировать наше сервер нам необязательно разворачивать его на впске, хоть нам и нужны протоколы SSL/TLS, из за того что браузеры (Chrome, Safari, Firefox) блокируют доступ к медиаустройствам на сайтах, работающих по незащищенному протоколу HTTP. Исключение составляет лишь
localhost
для целей локального тестирования. Мы можем воспользоваться tuna, который работает как полноценный аналог Ngrok. Основное назначение таких программ — создание безопасного туннеля, который дает прямой доступ из интернета к локальному серверу или приложению (
localhost
) без необходимости настраивать роутер и иметь «белый» IP-адрес.
